def compress_timeline(events):
    if not events:
        return []

    # Build difference array using coordinate compression
    diff = {}
    for s, e in events:
        if s >= e:
            continue
        diff[s] = diff.get(s, 0) + 1
        diff[e] = diff.get(e, 0) - 1

    coords = sorted(diff.keys())

    if len(coords) < 2:
        return []

    result = []
    active = 0
    for i in range(len(coords) - 1):
        active += diff[coords[i]]
        if active > 0:
            # Merge with previous interval if same count and adjacent
            if result and result[-1][1] == coords[i] and result[-1][2] == active:
                result[-1] = [result[-1][0], coords[i + 1], active]
            else:
                result.append([coords[i], coords[i + 1], active])

    return result
